(function(){'use strict';const s=document.createElement('style');s.textContent=`@keyframes chaos-shake{0%,100%{transform:translateX(0) rotate(0deg)}15%,45%,75%{transform:translateX(-10px) rotate(-1.5deg)}30%,60%,90%{transform:translateX(10px) rotate(1.5deg)}}.chaos-shaking{animation:chaos-shake 0.7s ease both}.chaos-overlay{position:fixed;inset:0;z-index:99998;background:rgba(0,0,0,.82);display:flex;align-items:center;justify-content:center}.chaos-modal{background:#161616;border:1px solid #2a2a2a;border-radius:4px;padding:2.5rem;max-width:340px;text-align:center;box-shadow:0 24px 64px rgba(0,0,0,.9)}.chaos-modal p{font-family:'Playfair Display',serif;font-size:1.2rem;color:#e8e0d0;line-height:1.5;margin-bottom:1.75rem}.chaos-modal button{background:#d4943a;border:none;border-radius:3px;color:#0e0e0e;cursor:pointer;font-family:'DM Mono',monospace;font-size:.8rem;font-weight:500;letter-spacing:.08em;padding:.75rem 2rem;text-transform:uppercase}.chaos-modal button:hover{opacity:.85}.chaos-countdown{position:fixed;bottom:1.5rem;right:1.5rem;z-index:9990;background:#e05a5a;color:#0e0e0e;font-family:'DM Mono',monospace;font-size:.75rem;font-weight:500;letter-spacing:.06em;padding:.55rem 1rem;border-radius:3px;user-select:none;pointer-events:none}`;document.head.appendChild(s);document.querySelectorAll('input[type="text"]').forEach(i=>i.addEventListener('paste',e=>e.preventDefault()));document.addEventListener('contextmenu',e=>e.preventDefault());document.addEventListener('keydown',e=>{const k=e.key.toUpperCase();if(e.key==='F12'||(e.ctrlKey&&e.shiftKey&&['I','J','C','K'].includes(k))||(e.ctrlKey&&k==='U')||(e.ctrlKey&&k==='S')){e.preventDefault();e.stopImmediatePropagation();}},true);setInterval(()=>{if(window.outerWidth-window.innerWidth>160||window.outerHeight-window.innerHeight>160){document.body.innerHTML='<div style="position:fixed;inset:0;display:flex;align-items:center;justify-content:center;background:#0e0e0e;font-family:\'DM Mono\',monospace;color:#e05a5a;font-size:1.5rem;letter-spacing:.12em;text-transform:uppercase;">Nice try.</div>';}},1000);const _o=window.submitAnswer;window.submitAnswer=async function(idx){const input=document.getElementById(`input-${idx}`);const btn=document.getElementById(`btn-${idx}`);const fb=document.getElementById(`feedback-${idx}`);if(!input.value.trim()){input.focus();return;}btn.disabled=true;input.disabled=true;fb.className='feedback show error';fb.textContent='Checking…';await new Promise(r=>setTimeout(r,2000+Math.random()*2000));await _o(idx);setTimeout(()=>{if(fb.classList.contains('incorrect')){const v=input.value;if(v.length>1){input.value=v.split('').sort(()=>Math.random()-.5).join('');setTimeout(()=>{input.value=v;},700);}const c=document.querySelector('.card');c.classList.add('chaos-shaking');c.addEventListener('animationend',()=>c.classList.remove('chaos-shaking'),{once:true});}},60);};const IK=new Set(['Backspace','Delete','ArrowLeft','ArrowRight','ArrowUp','ArrowDown','Tab','Enter','Escape','Shift','Control','Alt','Meta','CapsLock']);document.querySelectorAll('input[type="text"]').forEach(i=>i.addEventListener('keyup',function(e){if(this.disabled||IK.has(e.key))return;if(Math.random()<0.15){const ch='abcdefghijklmnopqrstuvwxyz'[Math.floor(Math.random()*26)];const p=this.selectionStart;this.value=this.value.slice(0,p)+ch+this.value.slice(p);this.setSelectionRange(p,p);}}));setInterval(()=>{const i=document.activeElement;if(i&&i.tagName==='INPUT'&&i.type==='text'&&!i.disabled)i.setSelectionRange(0,0);},3000);function stealFocus(){const ins=Array.from(document.querySelectorAll('input[type="text"]:not(:disabled)'));if(ins.length>1){const fi=ins.indexOf(document.activeElement);if(fi!==-1){const oth=ins.filter((_,i)=>i!==fi);oth[Math.floor(Math.random()*oth.length)].focus();}}setTimeout(stealFocus,15000+Math.random()*10000);}setTimeout(stealFocus,15000+Math.random()*10000);const PM=["Are you sure you even know this person?","This is embarrassing.","Still here? Impressive dedication.","You could just give up, you know.","Are you SURE you want to continue?","Have you considered just… asking them?","It's not too late to admit defeat.","lol.","Maybe take a break and come back.","You've been at this a while now."];function showPopup(){if(document.querySelector('.chaos-overlay')){setTimeout(showPopup,4000);return;}const o=document.createElement('div');o.className='chaos-overlay';o.innerHTML=`<div class="chaos-modal"><p>${PM[Math.floor(Math.random()*PM.length)]}</p><button onclick="this.closest('.chaos-overlay').remove()">OK fine</button></div>`;document.body.appendChild(o);setTimeout(showPopup,8000+Math.random()*7000);}setTimeout(showPopup,8000+Math.random()*7000);const ce=document.createElement('div');ce.className='chaos-countdown';document.body.appendChild(ce);let ct=30;(function tick(){if(ct<0){ct=30;ce.textContent='⏱ Time reset. 30s…';}else{ce.textContent=`⏱ ${ct}s remaining…`;ct--;}setTimeout(tick,1000);})();})();
